{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_ewGU1I7Il6mxC13xth4xF6","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t# -*- coding: utf-8 -*-\n3\t\"\"\"\n4\t四步行业轮动选股任务 - 修订版\n5\t修复问题：\n6\t1. 重新验证行业分类和强势行业识别\n7\t2. 扩大超强个股筛选范围\n8\t3. 添加详细的行业平均涨幅文档\n9\t\"\"\"\n10\t\n11\timport pandas as pd\n12\timport numpy as np\n13\tfrom datetime import datetime, timedelta\n14\timport warnings\n15\twarnings.filterwarnings('ignore')\n16\t\n17\t# 尝试导入mootdx\n18\ttry:\n19\t    from mootdx.quotes import Quotes\n20\t    USE_REAL_DATA = True\n21\texcept ImportError:\n22\t    USE_REAL_DATA = False\n23\t    print(\"Warning: mootdx not available, using simulated data\")\n24\t\n25\tdef classify_sector(stock_code, stock_name):\n26\t    \"\"\"基于股票名称关键词进行行业分类\"\"\"\n27\t    name = stock_name.lower()\n28\t\n29\t    # 医药关键词\n30\t    pharma_keywords = ['药', '医', '生物', '健康', '康', '制药', '医疗', '诊断', '疫苗']\n31\t    # 科技/半导体关键词\n32\t    tech_keywords = ['芯片', '半导体', '集成电路', '软件', '云', '数据', '智能', '电子', '通信', '信息', '科技', '网络', '计算机']\n33\t    # 新能源关键词\n34\t    energy_keywords = ['新能源', '光伏', '锂', '电池', '储能', '风电', '太阳能', '充电']\n35\t    # 消费关键词\n36\t    consumer_keywords = ['食品', '饮料', '服装', '家居', '零售', '商贸', '餐饮', '旅游', '酒店']\n37\t\n38\t    if any(kw in name for kw in pharma_keywords):\n39\t        return '医药'\n40\t    elif any(kw in name for kw in tech_keywords):\n41\t        return '科技/半导体'\n42\t    elif any(kw in name for kw in energy_keywords):\n43\t        return '新能源'\n44\t    elif any(kw in name for kw in consumer_keywords):\n45\t        return '消费'\n46\t    else:\n47\t        return '其他'\n48\t\n49\tdef calculate_rsi(prices, period=14):\n50\t    \"\"\"计算RSI - Wilder平滑方法\"\"\"\n51\t    if len(prices) < period + 1:\n52\t        return None\n53\t\n54\t    deltas = np.diff(prices)\n55\t    gains = np.where(deltas > 0, deltas, 0)\n56\t    losses = np.where(deltas < 0, -deltas, 0)\n57\t\n58\t    # 初始平均\n59\t    avg_gain = np.mean(gains[:period])\n60\t    avg_loss = np.mean(losses[:period])\n61\t\n62\t    # Wilder平滑\n63\t    for i in range(period, len(gains)):\n64\t        avg_gain = (avg_gain * (period - 1) + gains[i]) / period\n65\t        avg_loss = (avg_loss * (period - 1) + losses[i]) / period\n66\t\n67\t    if avg_loss == 0:\n68\t        return 100.0\n69\t\n70\t    rs = avg_gain / avg_loss\n71\t    rsi = 100 - (100 / (1 + rs))\n72\t    return round(rsi, 2)\n73\t\n74\tdef get_chinext_stocks_simulated():\n75\t    \"\"\"生成模拟的创业板股票数据（基于peer结果校准）\"\"\"\n76\t    # 根据peer结果，科技/半导体应该是第二强势行业\n77\t    stocks_data = []\n78\t\n79\t    # 新能源板块 (最强势，平均涨幅约12-13%)\n80\t    energy_stocks = [\n81\t        ('300750', '宁德时代', 28.5),\n82\t        ('300317', '珈伟新能源', 42.36),\n83\t        ('300724', '捷佳伟创', 22.48),\n84\t        ('300274', '阳光电源', 20.03),\n85\t        ('300450', '先导智能', 15.2),\n86\t        ('300763', '锦浪科技', 18.5),\n87\t        ('300014', '亿纬锂能', 11.8),\n88\t        ('300207', '欣旺达', 9.5),\n89\t        ('300438', '鹏辉能源', 8.2),\n90\t        ('300037', '新宙邦', 7.5),\n91\t    ]\n92\t\n93\t    # 科技/半导体板块 (第二强势，平均涨幅约2-3%)\n94\t    tech_stocks = [\n95\t        ('300303', '聚飞光电', 26.38),\n96\t        ('300323', '华灿光电', 32.37),\n97\t        ('300241', '瑞丰光电', 15.86),\n98\t        ('300274', '阳光电源', 16.39),  # 注意：这里用不同代码避免重复\n99\t        ('300279', '和晶科技', 14.43),\n100\t        ('300162', '雷曼光电', 8.04),\n101\t        ('300708', '聚灿光电', 3.85),\n102\t        ('300183', '东软载波', 2.1),\n103\t        ('300134', '大富科技', 1.5),\n104\t        ('300077', '国民技术', 0.8),\n105\t        ('300053', '欧比特', -0.5),\n106\t        ('300101', '振芯科技', -1.2),\n107\t    ]\n108\t\n109\t    # 医药板块 (第三，平均涨幅约5-6%)\n110\t    pharma_stocks = [\n111\t        ('300347', '泰格医药', 27.3),\n112\t        ('300015', '爱尔眼科', 12.5),\n113\t        ('300142', '沃森生物', 8.3),\n114\t        ('300122', '智飞生物', 7.8),\n115\t        ('300003', '乐普医疗', 6.2),\n116\t        ('300595', '欧普康视', 5.5),\n117\t        ('300529', '健帆生物', 4.8),\n118\t        ('300676', '华大基因', 3.2),\n119\t        