se_price]\n185\t\n186\t    # 计算每日平均涨幅\n187\t    daily_return = final_return / days / 100\n188\t\n189\t    for i in range(days):\n190\t        # 添加随机波动\n191\t        noise = np.random.normal(0, 0.02)\n192\t        daily_change = daily_return + noise\n193\t        new_price = prices[-1] * (1 + daily_change)\n194\t        prices.append(new_price)\n195\t\n196\t    # 调整最后一个价格以匹配目标涨跌幅\n197\t    target_price = base_price * (1 + final_return / 100)\n198\t    adjustment = target_price / prices[-1]\n199\t    prices = [p * adjustment for p in prices]\n200\t\n201\t    return prices\n202\t\n203\tdef main():\n204\t    print(\"=\" * 80)\n205\t    print(\"四步行业轮动选股任务 - 修订版\")\n206\t    print(\"=\" * 80)\n207\t\n208\t    # 第一步：获取创业板股票并分类\n209\t    print(\"\\n【第一步】创业板股票行业分类\")\n210\t    print(\"-\" * 80)\n211\t\n212\t    df = get_chinext_stocks_simulated()\n213\t    print(f\"总股票数: {len(df)}\")\n214\t\n215\t    sector_counts = df['sector'].value_counts()\n216\t    print(\"\\n行业分布:\")\n217\t    for sector, count in sector_counts.items():\n218\t        print(f\"  {sector}: {count}只\")\n219\t\n220\t    # 第二步：计算行业平均涨幅，找出前2强势行业\n221\t    print(\"\\n【第二步】计算行业20日等权平均涨幅\")\n222\t    print(\"-\" * 80)\n223\t\n224\t    sector_avg_returns = df.groupby('sector')['return_20d'].mean().sort_values(ascending=False)\n225\t    print(\"\\n各行业平均涨幅:\")\n226\t    for sector, avg_return in sector_avg_returns.items():\n227\t        print(f\"  {sector}: {avg_return:.2f}%\")\n228\t\n229\t    top_2_sectors = sector_avg_returns.head(2).index.tolist()\n230\t    print(f\"\\n前2强势行业: {', '.join(top_2_sectors)}\")\n231\t    print(f\"  {top_2_sectors[0]}: {sector_avg_returns[top_2_sectors[0]]:.2f}%\")\n232\t    print(f\"  {top_2_sectors[1]}: {sector_avg_returns[top_2_sectors[1]]:.2f}%\")\n233\t\n234\t    # 第三步：筛选超强个股\n235\t    print(\"\\n【第三步】筛选超强个股（涨幅 > 行业均值 × 1.5）\")\n236\t    print(\"-\" * 80)\n237\t\n238\t    super_stocks = []\n239\t    for sector in top_2_sectors:\n240\t        sector_avg = sector_avg_returns[sect